import{_ as i,o as l,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt3201.jpg",a="/images/lekt3202.jpg",s="/images/lekt3203.jpg",h="/images/lekt3204.jpg",d="/images/lekt3205.jpg",p="/images/lekt3207.jpg",o="/images/lekt3206.jpg",u="/images/lekt3208.jpg",m="/images/lekt3209.jpg",b="/images/lekt3210.jpg",v=JSON.parse('{"title":"Lektion 32","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion32.md","filePath":"lektionen/lektion32.md"}'),c={name:"lektionen/lektion32.md"};function g(k,e,f,w,z,q){return l(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-32" tabindex="-1">Lektion 32 <a class="header-anchor" href="#lektion-32" aria-label="Permalink to &quot;Lektion 32&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>32.1. Die Vergangenheitstempora</li><li>32.2. Das Imperfekt (लङ्)</li><li>32.3. Regeln für das Augment</li><li>32.4. Beispiele für die Imperfektbildung der einzelnen Präsensklassen <ul><li>32.4.1. Thematische Präsensklassen</li><li>32.4.2. Athematische Präsensklassen</li></ul></li><li>32.5. Wortliste</li><li>32.6. Übung</li><li>32.7. Übung zur Wiederholung über die Weihnachtsferien</li><li>32.8. Übung zur Wiederholung</li><li>32.9. Übersetzungsübung</li></ul><h2 id="_32-1-die-vergangenheitstempora" tabindex="-1">32.1. Die Vergangenheitstempora <a class="header-anchor" href="#_32-1-die-vergangenheitstempora" aria-label="Permalink to &quot;32.1. Die Vergangenheitstempora&quot;">​</a></h2><p>In der älteren Sanskritliteratur und von den einheimischen Grammatikern werden die drei Tempora der Vergangenheit in ihrem Gebrauch klar unterschieden:</p><ul><li>der Aorist (लुङ् , अद्यतनी) bezeichnet entweder einfach die Vollendung einer Handlung oder er bezeichnet, was sich am laufenden Tag ereignet hat, die nahe Vergangenheit</li><li>das Imperfekt (लङ्) bezeichnet, was sich vor dem laufenden Tage ereignet hat, die entfernte Vergangenheit</li><li>das Perfekt (लिट्) bezeichnet wie das Imperfekt die entfernte Vergangenheit, wird aber, im Gegensatz zum Imperfekt, nur von Ereignissen gebraucht, die der Sprechende selbst nicht gesehen hat</li></ul><p>In der klassischen Sanskritliteratur werden die drei Vergangenheitstempora ohne Bedeutungsunterschied gebraucht (Ausnahme: भारवि&#39;s Kunstgedicht  किरातार्जुनीय)</p><h2 id="_32-2-das-imperfekt-लङ्" tabindex="-1">32.2. Das Imperfekt (लङ्) <a class="header-anchor" href="#_32-2-das-imperfekt-लङ्" aria-label="Permalink to &quot;32.2. Das Imperfekt (लङ्)&quot;">​</a></h2><p>Bildung:</p><p>Augment a- + Präsensstamm + Sekundärendung</p><p>Die drei Personen des Singular Parasmaipada Imperfekt werden bei athematischen Stämmen vom starken Präsensstamm gebildet, alle übrigen Formen vom schwachen Präsensstamm.</p><p>Das Imperfekt hat nur den Indikativ.</p><p>Beispiele:</p><blockquote><p>भू 3. sg. Impf. P. अभवत् (a-bhava-t)</p><p>सु</p><ul><li>3. sg. Impf. P. असुनोत् (a-suno-t)</li><li>3. pl. Impf. P. असुन्वन् (a + sunu + an)</li></ul></blockquote><h2 id="_32-3-regeln-fur-das-augment" tabindex="-1">32.3. Regeln für das Augment <a class="header-anchor" href="#_32-3-regeln-fur-das-augment" aria-label="Permalink to &quot;32.3. Regeln für das Augment&quot;">​</a></h2><p>1. Tritt das Augment a- vor eine vokalisch anlautende Wurzel, so verschmelzen das Augment un der Wurzelanlaut zur वृद्धि des Wurzelvokals.</p><p>Beispiele:</p><blockquote><p>|   | 3.sg.Impf.</p><p>| 3.pl.Impf | | --- | --- | --- | | इष् |</p><p>ऐच्छत्<br> (a- + iccha-t)</p><p>|   | | इ | ऐत्<br> (a- + e + t) | आयन्<br> (a + i + an) | | आस् | आस्त<br> (a + ās-ta) |   |</p></blockquote><p>2. Stehen Präverbe vor einer Wurzel, so tritt das Augment a- hinter die Präverbe unmittelbar vor die Wurzel.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th></th><th>3.sg.Impf.</th></tr></thead><tbody><tr><td>आगम्</td><td></td></tr><tr><td>आगच्छत्</td><td></td></tr><tr><td>(ā + a + gaccha-t)</td><td></td></tr></tbody></table><p>| | संगम् | समगच्छत्<br> (sam-a-gaccha-t) | | उपगम् | उपागच्छत्<br> (upa + a + gaccha-t) | | उपागम् | उपागच्छत्<br> (upa + ā + a +gaccha-t) |</p></blockquote><h2 id="_32-4-beispiele-fur-die-imperfektbildung-der-einzelnen-prasensklassen" tabindex="-1">32.4. Beispiele für die Imperfektbildung der einzelnen Präsensklassen <a class="header-anchor" href="#_32-4-beispiele-fur-die-imperfektbildung-der-einzelnen-prasensklassen" aria-label="Permalink to &quot;32.4. Beispiele für die Imperfektbildung der einzelnen Präsensklassen&quot;">​</a></h2><p><img src="'+n+'" alt=""> Um die Bildung der Formen zu demonstrieren, werden hier auch zu Parasmaipada-Wurzeln Ātmanepada-Formen gebildet! Diese künstlichen Formen stehen zwischen &lt;&gt;.</p><h3 id="_32-4-1-thematische-prasensklassen" tabindex="-1">32.4.1. Thematische Präsensklassen <a class="header-anchor" href="#_32-4-1-thematische-prasensklassen" aria-label="Permalink to &quot;32.4.1. Thematische Präsensklassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Präsensklasse</th><th>Wurzel</th><th>3. sg.P</th><th>3.pl.P</th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><ol><li></li></ol><p>|</p><p>भू</p><p>|</p><p>अभवत्</p><p>|</p><p>अभवन्</p><p>|</p><p>&lt;अभवत&gt;</p><p>|</p><p>&lt;अभवन्त&gt;</p><p>| | 4. | नृत् | अनृत्यत् | अनृत्यन् | &lt;अनृत्यत&gt; | &lt;अनृत्यन्त&gt; | | 6. | विश् | अविशत् | अविशन् | &lt;अविशत&gt; | &lt;अविशन्त&gt; | | 10. und Kaus. | चुर् | अचोरयत् | अचोरयन् | अचोरयत | अचोरयन्त | | Passiv |   | 3.sg.Passiv | 3.pl.Passiv |   |   | |   | गम् | अगम्यत | अगम्यन्त |   |   |</p><h3 id="_32-4-2-athematische-prasensklassen" tabindex="-1">32.4.2. Athematische Präsensklassen <a class="header-anchor" href="#_32-4-2-athematische-prasensklassen" aria-label="Permalink to &quot;32.4.2. Athematische Präsensklassen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Präsensklasse</th><th>Wurzel</th><th>3. sg.P</th><th>3.pl.P</th><th>3.sg.Ā</th><th>3.pl.Ā</th></tr></thead><tbody><tr><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><ol start="2"><li></li></ol><p>| द्विष् | अद्वेट्<br> (adveṣṭ » adveṣ »  adveṭ) | अद्विषन्<br> अद्विषुर् | अद्विष्ट | अद्विषत | | 2. | दुह् | अधोक्<br> (a + doh +t » adogdh » adhok) | अदुहन् | अदुग्ध | अदुहत | | 2. | इ | ऐत् | आयन् |   |   | | 2. | हन् | अहन्<br> (aus *ahant) | अघ्नन् |   |   | | 2. | स्तु | अस्तौत्<br> अस्तवीत् | अस्तुवन् | अस्तुत | अस्तुवत | | 2. | अस् | आसीत् | आसन् |   |   | | 5. | सु | असुनोत् | असुन्वन् | असुनुत | असुन्वत | | 5. | आप् | आप्नोत् | आप्नुवन् | &lt;आप्नुत&gt; | &lt;आप्नुवत&gt; | | 8. | तन् | अतनोत् | अतन्वन् | अतनुत | अतन्वत | | 8. | कृ | अकरोत् | अकुर्वन् | अकुरुत | अकुर्वत | | 7. | युज् | अयुनक्<br> (a-yunaj + t » ayunakt » ayunak) | अयुञ्जन् | अजुङ्क्त<br> (a-yuñj + ta) | अजुञ्जत | | 7. | रुध् | अरुणत्<br> (a-ruṇadh + t » aruṇaddh » aruṇat) | अरुन्धन् | अरुन्द्ध | अरुन्धत | | 9. | क्री | अक्रीणात्<br> (a-krīṇā-t) | अक्रीणन्<br> (a-krīṇ-an) | अक्रीणीत<br> (a-krīṇī-ta) | अक्रीणत<br> (a-krīṇ-ata) |</p><h2 id="_32-5-wortliste" tabindex="-1">32.5. Wortliste <a class="header-anchor" href="#_32-5-wortliste" aria-label="Permalink to &quot;32.5. Wortliste&quot;">​</a></h2><p>अग्र n.: Spitze, äußerstes Ende</p><p>मही f.: Erde, Grund und Boden (wörtl.: die Große)</p><p>एकदा</p><p>श्रम् श्राम्यते</p><blockquote><p>श्रमिष्यते<br> श्रम्यते<br> श्रमयति<br> श्रान्त<br> श्रमित्वा । श्रान्त्वा<br> -श्रम्य<br> श्रमितुम्</p></blockquote><p>पार्श्व</p><p>चूत</p><p><img src="'+a+'" alt=""><br> Abb.: चूतः<br> कानपुर, / کان پور<br> [Bildquelle: AmarChandra / Wikipedia. -- <a href="http://en.wikipedia.org/wiki/Creative_Commons" title="w:Creative Commons" target="_blank" rel="noreferrer">Creative Commons</a> <a href="http://creativecommons.org/licenses/by-sa/2.5/" title="http://creativecommons.org/licenses/by-sa/2.5/" target="_blank" rel="noreferrer">Attribution ShareAlike 2.5</a> (Namensnennung, share alike)]</p><p>तरु वृक्ष</p><p>पचेलिम</p><p>स्पृहा</p><p>परम्</p><p>रुह् रोहति</p><blockquote><p>रोक्ष्यति<br> रुह्यते<br> रोहयति । रोपयति<br> रूढ<br> -रुह्य<br> रोढुम्</p></blockquote><p>ग्रह् गृह्णति</p><blockquote><p>ग्रहीष्यति (!)<br> गृह्यते<br> ग्राहयति<br> गृहीत<br> -गृह्य<br> ग्रहीतुम् (!)</p></blockquote><p>वानर कपि</p><p><img src="'+s+'" alt=""><br> Abb.: वानराः<br> Delhi = दहली<br> [Bildquelle: dewalt. -- <a href="http://www.flickr.com/photos/dewalt/389870377/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dewalt/389870377/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>लोक् लोकयति</p><blockquote><p>लोकयिष्यति<br> लोक्यते<br> लोकित<br> -लोक्य<br> लोकितुम्</p></blockquote><p>प्रहर्ष</p><p>कति</p><p>उपल</p><p><img src="'+h+'" alt=""><br> Abb.: उपलाः</p><blockquote><p>&quot;The boulders here are hard enough that the scavengers who have taken over the abandoned quarry south of downtown prefer not to strike them directly with their hammers.They heat the rocks first  with flaming tires, scrap plastic, even old rubber boots  so that the stones will fracture more easily. At dusk, when three or four blazes spew choking black clouds across the huge pit, the quarry looks like a woodcut out of Dante. At the mouth of this stone quarry in Pune Maharashtra, diminutive women in saris toil 14 hour shifts breaking boulders into cricket-ball sized chunks of stone. Sledgehammers cut through to the air to the sound of splintering stone. Just behind them roared large machines that chewed up stone only to spit out construction gravel. Almost everybodies face was smeared with a white dust. A dust, heavy and suffocating, floating in the air like mist covering everything.&quot;</p><p>[Bildquelle: lecercle. -- <a href="http://www.flickr.com/photos/lecercle/2304674715/in/set-72157604058089822/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lecercle/2304674715/in/set-72157604058089822/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p></blockquote><p>लक्ष्य</p><p><img src="'+d+'" alt=""><br> Abb.: लक्ष्यम्<br> Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/321235900/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/321235900/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Bearbeitung)]</p><p>क्षिप् क्षिपति</p><blockquote><p>क्षेप्स्यति<br> क्षिप्यते<br> क्षेपयति<br> क्षिप्त<br> -क्षिप्य<br> क्षेप्तुम्</p></blockquote><p>चि चिनोति</p><blockquote><p>चेष्यति<br> चीयते<br> चाययति<br> चित<br> -चित्य<br> चेतुम्</p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: चितं गोमयं दहति (गोमय n.: Kuhmist)<br> Rajasthan<br> [Bildquelle: thebigdurian. -- <a href="http://www.flickr.com/photos/thebigdurian/29862842/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/thebigdurian/29862842/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>चि अव</p><p>प्रति</p><p>अहो</p><p>कौशल कुशल</p><p><img src="'+o+'" alt=""><br> Abb.: कौशलम्<br> Mehndi = मेहन्दी, Mumbai = मुंबई<br> [Bildquelle: the_gman. -- <a href="http://www.flickr.com/photos/thegman/2860162252/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/thegman/2860162252/</a>. -- Zugriff am 2008-12-25. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_32-6-ubung" tabindex="-1">32.6. Übung <a class="header-anchor" href="#_32-6-ubung" aria-label="Permalink to &quot;32.6. Übung&quot;">​</a></h2><p>A) Bestimmen Sie folgende Verbformen und bilden Sie die in Person, Zahl und Genus verbis entsprechenden Imperfektformen:</p><ol><li>हरि्ष्यन्ते</li><li>घातयति</li><li>विहन्ति</li><li>घ्नन्ति</li><li>विस्मर्यते</li><li>प्रस्थास्यन्ते</li><li>प्रस्तुते</li><li>स्रक्ष्यन्ति</li><li>सेक्ष्यन्ति</li><li>श्रूयते</li><li>शक्नोति</li><li>वर्त्स्यन्ति</li><li>वसते</li><li>वत्स्यन्ति</li><li>वदति</li><li>प्रवक्ति</li><li>वेशयन्ते</li><li>लुभ्यन्ति</li><li>उपलप्स्यन्ते</li><li>रुन्द्धे</li><li>रोदिति</li><li>रक्षन्ति</li><li>युध्यन्ते</li><li>युञ्जते</li><li>युजन्ति</li><li>म्रियते</li><li>विमोचयन्ति</li><li>मंस्यन्ते</li><li>मोहिष्यति</li><li>भवति</li><li>भुनक्ति</li><li>भिनत्ति</li><li>भञ्जन्ति</li><li>भजते</li><li>ब्रूते</li><li>विजेष्यन्ते</li><li>जायन्ते</li><li>छिन्त्ते</li><li>आचरन्ति</li><li>चोर्यन्ते</li><li>आगमिष्यन्ति</li><li>कामयन्ते</li><li>खादन्ति</li><li>विक्रेष्यते</li><li>संस्करोति</li><li>क्रुध्यन्ति</li><li>एषयन्ति</li><li>संयन्ति</li><li>समास्ते</li><li>व्यङ्क्ते</li><li>सन्ति</li><li>अस्यन्ति</li><li>अश्नाति</li><li>अश्नुते</li><li>प्राप्स्यन्ति</li><li>अदन्ति</li><li>प्रभोत्स्यन्ते</li><li>बध्नाति</li><li>प्रक्ष्यन्ति</li><li>पुनाति</li><li>पान्ति</li><li>पास्यन्ति</li><li>पद्यते</li><li>पातयति</li><li>पक्ष्यन्ति</li><li>नर्तिष्यति</li><li>आनेष्यन्ति</li><li>द्वेष्टि</li><li>द्रक्ष्यन्ति</li><li>दूषयन्ति</li><li>उपदेक्ष्यन्ति</li><li>धक्ष्यति</li><li>तनोति</li><li>प्रजानीते</li><li>जीवन्ति</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>आसीत्क्षत्रिय उपपन्नो गुणैरिष्टै रूपवान् । स जनेन्द्राग्रे ऽतिष्ठत् । स देवानयजतारीनजयज्जनानपान्महापुण्यमकरोत् । तस्मान्मृत्वा देवलोके पुनर्भवमलभत ॥१॥</p><p>ब्राह्मणो महानगरे ऽवसत् । स पुत्रमागमय्यावक् । ब्राह्मणपुत्रो वेदं गुरावधीयीतेति । तच्छ्रुत्वा स पुत्रो ऽध्ययनाय गुरुमैत् । गुरुगृहे प्रविश्य गुरुमुपातिष्ठद्गुरुश्च तं पुत्रम् ब्राह्मणमपृच्छत् । ततस्तेन पुत्रेणान्नमादयत् ॥२॥</p><p>राम आचर्यमुपसंगम्य वचनमब्रवीत् ॥३॥</p><p>ब्राह्मणा वेदमध्यैयत चाध्यापयंश्च देवांश्चायजन्नयजन्त च क्षत्रियाः श्रुतिमध्यैयत जनानरक्षन्महीमभुञ्जन्देवानयजन्त वैश्या वेदमध्यैयत देवानयजन्ताक्रीणन्व्यक्रीणत च द्विजदासास्तु शूद्रा आसन् ॥४॥</p><p>बुद्धपुत्राः सत्यमजानन्दुःखमरुन्धन्मोक्षं प्राप्नुवन् । बुद्धपुत्र इति बुद्धमार्गभिक्षुरुच्यते ॥५॥</p><p><img src="'+u+'" alt=""><br> Abb.: बुद्धपुत्र इति बुद्धमार्गभिक्षुरुच्यते<br> Sri Lanka<br> [Bildquelle: Trollderella / Wikipedia. GNU FDLicense]</p><h2 id="_32-7-ubung-zur-wiederholung-uber-die-weihnachtsferien" tabindex="-1">32.7. Übung zur Wiederholung über die Weihnachtsferien <a class="header-anchor" href="#_32-7-ubung-zur-wiederholung-uber-die-weihnachtsferien" aria-label="Permalink to &quot;32.7. Übung zur Wiederholung über die Weihnachtsferien&quot;">​</a></h2><p>Anmerkung: ursprünglich wurde dieser an der Universität Tübingen jeweils im Wintersemester gehalten. Bei Lektion 32 begannen die zweiwöchigen Weihnachtsferien.</p><p>A) Bestimmen und übersetzen Sie folgende Wörter:</p><ol><li>देवस्य</li><li>उषितायाः</li><li>लप्स्यन्ते</li><li>गुरौ</li><li>भाव्यते</li><li>अग्नये</li><li>मोक्तुम्</li><li>वितत्य</li><li>स्मृत्यै</li><li>देवताः</li><li>ब्रवीति</li><li>प्रक्ष्यन्ति</li><li>पततः</li><li>पत्स्यन्ते</li><li>आसते</li><li>महान्ति</li><li>घ्नता</li><li>आययन्ति</li><li>एषिता</li><li>आनाय्य</li><li>अनृताय</li><li>पूजया</li><li>प्रश्नेभ्यः</li><li>धक्ष्यन्ति</li><li>मृगान्</li><li>बोधिम्</li><li>गुणैः</li><li>सन्ति</li><li>यन्ति</li><li>क्रियते</li><li>विगत्य</li><li>चरित्वा</li><li>पीते</li><li>अन्नानि</li><li>जलम्</li><li>वक्ति</li><li>उक्तिः</li><li>अर्धात्</li><li>अर्थेन</li><li>स्तूयन्ते</li><li>श्रोष्यति</li><li>स्रष्टुम्</li><li>पशुम्</li><li>स्तुतीः</li><li>अरयः</li><li>जात्या</li><li>जाताम्</li><li>देक्ष्यति</li><li>दर्शितः</li><li>दुष्टाः</li><li>द्विजातीन्</li><li>मृत्योः</li><li>दुग्धानाम्</li><li>दिष्टिभिः</li><li>मात्रायाम्</li><li>अत्ति</li><li>जायन्ते</li><li>जीयन्ते</li><li>जयन्ति</li><li>जनयन्ति</li><li>प्रभृतेः</li><li>उपतिष्ठन्ति</li><li>स्थित्याम्</li><li>भिक्षुषु</li><li>पक्त्वा</li><li>योद्धुम्</li><li>मारयित्वा</li><li>धेन्वा</li><li>मंस्यन्ते</li><li>इज्यते</li><li>प्रोद्य</li><li>लम्भयति</li><li>स्थापिताभिः</li><li>शक्तिभ्यः</li><li>अलम्</li><li>हेतून्</li><li>प्रतिमासु</li><li>यस्याः</li><li>हि</li><li>तस्मिन्</li><li>ह्रियन्ते</li><li>अधिकृतेषु</li><li>अध्यापयति</li><li>वाचयन्ति</li></ol><p>B) Übung zum Sandhi: Setzen Sie in folgenden Sätzen die Wörter in den Klammern ein. Achten Sie dabei besonders auf den Sandhi:</p><p>१. रामो ग्रामात् ... (द्वितीया विभक्तिः) ... गच्छति । (नगर । आर्यग्राम । महानगर । शत्रुग्राम । जयनगर । लोकेश्वरनगर । कविगृह )</p><p>२. जयन् ... (प्रथमा विभक्तिः) ... अरीन्हन्ति । (इन्द्रशत्रु । शत्रु । जितशत्रुक्षत्रिय । लोकेश्वर । तद्गुणशूर । देवता)</p><p>३. न हि पुण्यवन्तस्ते ... (प्रथमा विभक्तिः) ... । (अरि । आर्यशत्रु)</p><p>४. देवता ... (तृतीया विभक्तिः) ... आद्यते । (ऋषि (एकवचने बहुवचने च) । इन्द्रदेवी)</p><p>५.ब्राह्मणस् ... (सप्तमी विभक्तिरेकवचने बहुवचने च) ... एति । (नगर)</p><p>६. रामो गृहे ... । (आस् । इ । वस्)</p><p>७. शूरेण ... (प्रथमा विभक्तिः) ... जीयते । (अरि । इन्द्रशत्रु । उक्तानृतनर । एष नर)</p><p>८. कविना... (प्रथमा विभक्तिः) ... स्तूयन्ते । (आर्यदेव । इन्द्रादिदेव)</p><p>९. रामस् ... (द्वितीया विभक्तिः) ... गच्छति । (कवि । गृह । आर्यग्राम । अरिनगर । सुखता । तन्नगर । शूद्रग्राम । चन्द्रकीर्ति । ट्युबिङ्गन्नगर)</p><p>C) Übersetzen Sie ins Sanskrit:</p><p>1.) Nachdem der Sohn qeboren ist , schickt die Brahmanin einen Diener zum Brahmanen. Der Brahmane lässt diesen Diener ins Haus eintreten und fragt dann nach dem Sohn. Der Diener sagt, dass der Sohn wohlauf ist. Als er das qehört hat, wird der Brahmane glücklich.</p><p>2.) Der Heilige hat das (ihm) getane Böse ertragen.</p><p>3.) Sittlichkeit ist des Mannes Zier.</p><p>4.) Die mächtigen Krieger sind ins Brahmanendorf gegangen.</p><p>5.) Das Mädchen weint.</p><p>6.) Es gibt keine Krankheit gleich wie die Wohllust, es qibt keinen Feind wie die Verwirrung, es gibt kein Feuer wie den Zorn, es gibt kein Glück wie die Erkenntnis.</p><p>7.) Ein Mann, den die Göttin behütet, ist glücklich.</p><p>8.) Mit welchem Wind auch immer eine Wolke Wasser (वारि n.) lässt, mit dem Wind bewegt ein Gelehrter seinen Schirm.</p><p>9.) Es qibt keine fruchtbringenden Tätigkeiten von Ständen, Lebensstadien usw.</p><ol start="10"><li><p>Der Kreislauf der Wiedergeburten hat keinen Anfang.</p></li><li><p>Es ist Zeit, sich dem Essen zu widmen.</p></li><li><p>Willkommen der Königin.</p></li><li><p>Um der Himmel Willen tun die Menschen Verdienstvolles.</p></li><li><p>Ein Mann, der aus Überheblichkeit, Gier, Zorn, oder Furcht ein Gerichtsurteil fälschlich spricht, qeht in eine Hölle.</p></li><li><p>Rāma ging auf Anweisung der Lehrers aus dem Dorf in die Stadt, betrat das Haus des heiligen Mannes, trat ehrerbietig vor den Heiligen und spricht: &quot;Lass ab vom Zorn!&quot;</p></li><li><p>Immer (sei seine) Verbindung mit solchen, die in den Wissenschaften gewachsen sind, auf dass seine Erziehunq/qutes Verhalten wachse. (Dies) weil die Erziehunq/gutes Verhalten als Wurzel dieses (die Verbindung mit solchen) hat.</p></li><li><p>Während der Lehrer steht, darf der Knabe nicht sitzen.</p></li><li><p>Es gibt keine bessere Zuflucht als Rāma.</p></li><li><p>Viṣṇumitra lässt den Rāma den Govinda ins Dorf schicken.</p></li><li><p>Er lässt den Devadatta Reis kochen.</p></li><li><p>Dharma der Arier ist, dass junge Brahmanen die Abschnitte des Veda und der Smṛti immer wieder studieren</p></li><li><p>Der Lehrer lehrte die Knaben den Veda und ging dann ins Haus.</p></li><li><p>Welches Amulett hat das Mädchen beschützt?</p></li><li><p>Wahrheit ist die Leuchte der Welt.</p></li><li><p>Wem gehören diese Häuser?</p></li><li><p>Dharma aller ist: Nichtverletzen, Wahrheit, Reinheit, Neidlosiqkeit, Nicht-Boshaftigkeit und Geduld:</p></li><li><p>Die Kṣatriyas, die die Feinde besiegt haben, sitzen im Haus.</p></li><li><p>Die ist eine (wirkliche) Gattin, die Liebes spricht; der aber ist ein (echter) Sohn, der lebt. Der lebt, der gute Eigenschaften besitzt; der lebt, der Dharma besitzt.</p></li><li><p>Der Götterfürst besiegt die Nichtarier, die Feinde des Indra sind. (Passiv)</p></li><li><p>Yoga der Tat sind Askese (tapas n.), (Veda)rezitation, Dienstfertigkeit qegenüber dem HERRN. Er dient der Entfaltung der meditativen Versenkung und der Schwächung der kleśas.</p></li><li><p>Nahrungsaufnahme, Schlaf, Furcht und Paarung: dies ist eine Gemeinsamkeit der Menschen mit den Tieren. Im Dharma (liegt) nämlich deren hinzukommende Besonderheit. Vom Dharma verlassen sind sie den Tieren (Instr.) gleich.</p></li><li><p>Die Leute werden geboren, um zu sterben.</p></li><li><p>Höllen sind wegen des Bösen. Das Böse hat als Ursprung Armut. Armut entsteht durch Nicht-Geben.</p></li><li><p>Es ist Dharma der Kṣatriyas, dass die Kṣatriyas die Leute vor den Feinden schützen.</p></li><li><p>Deshalb haben die drei (tisras) Wissenschaften das Regiment als Wurzel. Das Reqiment , das Erziehunq/qutes Verhalten als Wurzel hat, bringt den Lebewesen (प्राणभृत्) Gewinn und sicheren Besitz.</p></li><li><p>Böse Leute hören nicht (zu), wenn der Lehrer über den Dharma spricht.</p></li><li><p>Diesem Rāma sei Verehrunq!</p></li><li><p>Der hehre Hari ist mein Weq/Ziel, der (seine) Feinde in einen Himmel schickte, die Seinen den Sinn des Veda wissen ließ, den Göttern Unsterblichkeitsspeise zu essen qab, den Schöpfer (विधि) den Veda lehrte, die Erde im Wasser (fest )setzte.</p></li><li><p>Viṣṇu zeiqt sich seinen Gläubiqen.</p></li><li><p>Ein Reqiment, das nicht ausgeübt wird, bewirkt die Norm der Fische.</p></li><li><p>Wer Reichtümer besitzt, der hat Freunde: wer Reichtümer besitzt, der hat Verwandte; wer Reichtümer besitzt, der ist ein Mann (पुमान् Nom.sq.) in der Welt; wer Reichtümer besitzt, der ist nämlich ein Gelehrter.</p></li><li><p>Das Feuer, das den Verstorbenen verbrennt, verbrennt auch die qute Witwe.</p></li><li><p>Die Dienerin des Brahmanen hat die Speise qekocht und isst sie (nun).</p></li><li><p>Jetzt reicht&#39;s !</p></li><li><p>Diese Frucht reicht ihm zum Essen.</p></li><li><p>Der innerste Tempelschrein ist ein Haus für das Bildnis des Gottes.</p></li><li><p>Ein Dieb wird vom Diebstahl befreit durch Strafe oder durch Freilassung, Wenn aber der König (राजा Nom.sg.) den (Dieb) nicht bestraft, erhält er die Schuld des Diebes.</p></li><li><p>Weil er einen Fehler beim Opfer gemacht hat, ist der Brahmane nicht würdig, Reichtümer zu empfangen.</p></li><li><p>Wenn die Initiationszeremonie stattqefunden hat, soll er sich den Veda und die Philosophie von Gelehrten, die Ökonomie von Departementsvorstehern aneignen (उपयुज्).</p></li><li><p>Vaiśyadharma ist, dass die Vaiśyas von Kauf und Verkauf leben. Da es so ist, kaufen und verkaufen die Vaiśyasöhne.</p></li><li><p>Man soll die Wahrheit saqen, man soll Anqenehmes sagen; man soll nicht eine unanqenehrne Wahrheit saqen und man soll auch keine unangenehme Unwahrheit saqen. Dies ist der ewige Dharma.</p></li><li><p>Auf Wiedersehen!</p></li></ol><p><img src="'+m+'" alt=""><br> Abb.: पुनर्दर्शनाय<br> [Bildquelle: dhyanji. -- <a href="http://www.flickr.com/photos/dhyanji/450566126/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dhyanji/450566126/</a>. -- Zugriff am 2008-12-26. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_32-8-ubung-zur-wiederholung" tabindex="-1">32.8. Übung zur Wiederholung <a class="header-anchor" href="#_32-8-ubung-zur-wiederholung" aria-label="Permalink to &quot;32.8. Übung zur Wiederholung&quot;">​</a></h2><p>Übersetzen und bestimmen Sie folgende Wortformen:</p><ol><li>अदुग्ध</li><li>स्युः</li><li>शूद्रायै</li><li>धेन्वाम्</li><li>दास्याः</li><li>आस्त</li><li>आनक्</li><li>साध्वीः</li><li>प्राजानत</li><li>अद्युः</li><li>आसीत्</li><li>हरौ</li><li>यस्याः</li><li>सता</li><li>तासु</li><li>तन्वीत</li><li>अकुरुत</li><li>आगमय्य</li><li>ताः</li><li>क्रेष्यन्ति</li><li>वसन्तानाम्</li><li>अतन्वत</li><li>अध्यैयत</li><li>गुर्व्यै</li><li>हराय</li><li>हारयत्</li><li>आहारयत्</li><li>हेतुभिः</li><li>धर्मवतः</li><li>एनया</li><li>तस्याम्</li><li>वेक्ष्यति</li><li>अद्विषुः</li><li>शक्तयः</li><li>आगमेभ्यः</li><li>व्यघ्नन्</li><li>भिन्दीरन्</li><li>भगवते</li><li>यत्सु</li><li>रोत्स्यन्ती</li></ol><h2 id="_32-9-ubersetzungsubung" tabindex="-1">32.9. Übersetzungsübung <a class="header-anchor" href="#_32-9-ubersetzungsubung" aria-label="Permalink to &quot;32.9. Übersetzungsübung&quot;">​</a></h2><p>एकदा कश्चिद्वृद्धो ग्रामान्तरं गच्छन्पथि श्रान्तो ऽभवत् । अतः स विश्रमाय पार्श्वस्थितस्य चूततरोर्मूलमगच्छत् ॥ तस्मिन्वृक्षे पचेलिमानि फलान्यवर्तन्त । वृद्धस्य तेषु स्पृहा जाता । परं स वृक्षमारुह्य तानि ग्रहीतुं नाशक्नोत् ॥ दिष्ट्या तस्मिन् तरौ केचिद्वानराः फलानि खादन्तः स्थिताः । तानवलोक्य वृद्धः प्रहर्षं गतः । स किमकरोत् । स कतिचिदुपलानादाय वानरांल्लक्ष्यीकृत्य प्राक्षिपत् । वानराः कुपिताः कानिचित्फलान्यवचित्य वृद्धं प्रति प्राक्षिपन् । वृद्धः सहर्षं तान्यादाय स्वाभीष्टदेशं गतः ॥ अहो वृद्धस्य कौशलम् ॥ (aus: संस्कृतबालादर्श)</p><p>Erklärungen:</p><p>पथि Lok. sg. zu पथ् m. &quot;Weg&quot; (unregelmäßige Deklination)</p><p>लक्ष्यीकृ च्विऽ-षुffइx अन् लक्स्य + कृ : etwas zum लक्ष्य machen, was vorher nicht लक्ष्य war</p><p>आदाय Absolutiv zu आ-दा (3. Präsensklasse) &quot;nehmen&quot;</p><p><img src="'+b+'" alt=""><br> Abb.: तस्मिन्वृक्षे पचेलिमानि फलान्यवर्तन्त<br> [Bildquelle: Wikipedia. GNU FDLicense]</p>',126)])])}const D=i(c,[["render",g]]);export{v as __pageData,D as default};
